import{_ as e,o,c as a,a3 as r}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"Export / Import Note Package","description":"","frontmatter":{},"headers":[],"relativePath":"export-import.md","filePath":"export-import.md","lastUpdated":1784665499000}'),i={name:"export-import.md"};function d(s,t,n,l,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="export-import-note-package" tabindex="-1">Export / Import Note Package <a class="header-anchor" href="#export-import-note-package" aria-label="Permalink to &quot;Export / Import Note Package&quot;">​</a></h1><p>Notely can package one or more notes — together with all their linked assets — into a single portable <code>.note</code> file that can be shared with other Notely users and imported directly into any workspace.</p><h2 id="opening-the-dialog" tabindex="-1">Opening the dialog <a class="header-anchor" href="#opening-the-dialog" aria-label="Permalink to &quot;Opening the dialog&quot;">​</a></h2><p>Go to <strong>File → Export / Import Note Package</strong> (or use the app menu from the landing screen).</p><p>The dialog has two tabs:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Export Package</strong></td><td>Bundle selected notes into a <code>.note</code> file</td></tr><tr><td><strong>Import Package</strong></td><td>Unpack a <code>.note</code> file into the current workspace</td></tr></tbody></table><h2 id="exporting" tabindex="-1">Exporting <a class="header-anchor" href="#exporting" aria-label="Permalink to &quot;Exporting&quot;">​</a></h2><ol><li><strong>Select notes</strong> — the list shows every <code>.md</code> file in the current workspace. Use <strong>Select All / Deselect All</strong> or click individual rows. The list scrolls when the workspace is large.</li><li><strong>Save location</strong> — defaults to the last-used export path with the filename <code>{workspaceName}.note</code>. Click <strong>Browse</strong> to choose a different destination.</li><li><strong>Password (Optional)</strong> — set a password to restrict who can import the package. If set, a salted SHA-256 hash of the password is saved securely inside the encrypted metadata.</li><li>Click <strong>Export Package</strong>.</li></ol><h3 id="what-gets-bundled" tabindex="-1">What gets bundled <a class="header-anchor" href="#what-gets-bundled" aria-label="Permalink to &quot;What gets bundled&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Asset type</th><th>Where it lives</th><th>Included</th></tr></thead><tbody><tr><td>Markdown files</td><td>anywhere in the workspace</td><td>✅</td></tr><tr><td>Images / screenshots</td><td><code>media/images/</code></td><td>✅</td></tr><tr><td>Excalidraw diagrams</td><td><code>.notes-app/excali-diagrams/</code></td><td>✅</td></tr><tr><td>Draw.io diagrams + thumbnails</td><td><code>media/draw.io/</code></td><td>✅</td></tr><tr><td>Package metadata</td><td><code>metadata.json</code> inside bundle</td><td>✅ auto-generated</td></tr></tbody></table><p>Assets that are locked, missing, or inaccessible at export time are silently skipped; the note itself is still exported.</p><h3 id="security" tabindex="-1">Security <a class="header-anchor" href="#security" aria-label="Permalink to &quot;Security&quot;">​</a></h3><ul><li>The bundle is <strong>AES-256 encrypted</strong> using a shared app-level key so it is not readable by generic ZIP tools.</li><li>Every file in the bundle is <strong>SHA-256 hashed</strong> and the hashes are stored in <code>metadata.json</code>. On import, Notely verifies each hash and rejects tampered packages.</li><li>If protected by a password, the manifest contains a salted <code>SHA-256</code> password signature. Unlocking verification occurs securely in memory during the import sequence before files are written.</li></ul><h2 id="importing" tabindex="-1">Importing <a class="header-anchor" href="#importing" aria-label="Permalink to &quot;Importing&quot;">​</a></h2><ol><li>Switch to the <strong>Import Package</strong> tab.</li><li>Click <strong>Browse</strong> and pick a <code>.note</code> file.</li><li>Click <strong>Import Package</strong>.</li><li><strong>Password Prompts</strong>: If the package is password-protected, the app will display a password field. Enter the correct password and click <strong>Import Package</strong> again to proceed.</li></ol><p>Notely will:</p><ul><li>Decrypt and verify the integrity of the bundle.</li><li>Authenticate the password if password protection was configured.</li><li>Copy notes into the workspace root (or appropriate subfolder).</li><li>Restore all media assets to their original relative paths.</li><li>Resolve filename collisions automatically so existing files are never overwritten.</li><li>Reload the workspace document list so imported notes appear immediately.</li></ul><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Symptom</th><th>Likely cause</th><th>Fix</th></tr></thead><tbody><tr><td>&quot;Export failed: EPERM&quot;</td><td>Destination folder is inside an OneDrive-synced path being actively synced</td><td>Wait a moment and retry, or choose a local (non-OneDrive) folder</td></tr><tr><td>&quot;Import failed: integrity check&quot;</td><td>The <code>.note</code> file was modified or corrupted in transit</td><td>Request a fresh export from the sender</td></tr><tr><td>&quot;Incorrect password&quot; or prompt stays</td><td>The password supplied does not match the package hash</td><td>Confirm the password with the package creator</td></tr><tr><td>Notes appear in workspace root instead of a subfolder</td><td>Package was exported from a flat workspace</td><td>Expected — the import mirrors the original layout</td></tr></tbody></table>',19)])])}const m=e(i,[["render",d]]);export{g as __pageData,m as default};
